<template>
    <header>
            <div class="header-content">
                <div class="header-content__logo" @click="goHome">
                    <div class="header-content__img-wrapper">
                        <img src="../assets/images/logo.png" class="header-content__img">
                    </div>
                    <div class="header-content__article">
                        GITGRAB
                    </div>
                </div>
                <div class="header-content__search">
                    <input type="text" placeholder="Input user's name here" v-model="search" @keyup.enter="submit" @blur="search=''">
                </div>
            </div>
        </header>
</template>

<script>
import * as types from '../store/mutation-types'
export default {
  name: 'Header',
  data() {
    return {
      search: ''
    }
  },
  methods: {
    submit() {  
      let name = this.search;
      this.search = '';
      this.$router.push({path: `/${name}`, params: { name}})
    },
    goHome () {
      this.search = '';
      this.$store.commit(types.CLEAR_ALL);
      this.$router.push({name: 'home'})
    }
  }
}
</script>

<style lang="less">

@import "../assets/less/style";

 header {
        display: flex;
        width: 100%;
        min-width: @default-width;
        height: 50px;
        background-color: @main-color;
    }
    .header-content {
        display: flex;
        justify-content: space-between;
        width: 960px;
        margin: auto;
    }
    .header-content__logo {
        display: inline-flex;
        align-items: center;
        padding-left: 10px;       
    }
    .header-content__img {
        width: 30px;
        height: 30px;
    }
    .header-content__img-wrapper {
        display: flex;
        justify-content: center;
        align-items: center;
        background-color: @text-color-reversed;
        border-radius: 50%;
        width: 40px;
        height: 40px;
    }
    .header-content__article {
        font-size: 20px;
        margin-left: 10px;
        color: @text-color-reversed;
    }
    .header-content__search {
        display: flex;
        align-items: center;
        padding-right: 10px;
    }
    
</style>

<style scoped  lang="less">
    @import "../assets/less/style";
    input {
        border-radius: 3px;
        background: lighten(@main-color, 30%);
        border: none;
        padding: 5px;
        &:focus {
            background: #fff;
        }
    }
</style>
