<template>
    <div>
        <div class="row" v-for = "(item, index) in items" :key="index" v-if="item.value">
            <div class="col">
                {{item.label}}
            </div>
            <div class="col">
                <div v-if = "urlChecker(item.value)">
                    <a :href="item.value">{{item.value}}</a>
                </div>
                <div v-else>{{item.value}}</div>
            </div>
        </div>
    </div>
</template>

<script>
import moment from 'moment'

export default {
    props: ['user'],
    methods: {
        urlChecker: function (value) {
            if (!value) return false
            let RegExp = /^((ftp|http|https):\/\/)?(www\.)?([A-Za-zА-Яа-я0-9]{1}[A-Za-zА-Яа-я0-9\-]*\.?)*\.{1}[A-Za-zА-Яа-я0-9-]{2,8}(\/([\w#!:.?+=&%@!\-\/])*)?/;
            return RegExp.test(value)
        }
    },
    data () {
        return {
            items: [
                {value: this.user.name, label: 'Name'},
                {value: this.user.email, label: 'E-mail'},
                {value: this.user.company, label: 'Company'},
                {value: this.user.blog, label: 'Blog'},
                {value:this.user.bio, label: 'BIO'},
                {value: moment(this.user.created_at, "YYYY-MM-DD").fromNow(), label: 'Created at'},
                {value: moment(this.user.updated_at, "YYYY-MM-DD").fromNow(), label: 'Updated at'},
                {value: this.user.followers, label: 'Followers'},
                {value: this.user.following, label: 'Following'},
                {value: this.user.hireable, label: 'Hireable'},
                {value: this.user.location, label: 'Location'},
                {value: this.user.public_repos, label: 'Public repositories'},
            ]
        }
    }
}
</script>

<style scoped lang="less">
    .row {
        display: inline-flex;
        width: 100%;
        flex-wrap: wrap;
        border-bottom: 1px solid lightgrey;
    }
    .col {
        display: flex;
        width: 45%;
        padding: 5px;
    }
</style>

