<template>
    <div class="repo-list">
        <div v-for="(item, index) in repoList.repos" :key="index" class="repo-list__container">
                <div class="row">
                    <div class="col repo-list__link" @click="goTo(index)">
                        {{item.name}}
                    </div>
                </div>
                <div class="row" v-if="item.description">
                    <div class="col repo-list__description">
                        {{item.description}}
                    </div>
                </div>
                <div class="row repo-list__info" v-if = "item.language">
                    <div class="col">
                        <icon name = "circle" :color = "item.language | colorize"/> {{item.language}}
                    </div>
                    <div class="col" v-if ="item.stargazers_count > 0">
                        <icon name = "star"/> {{item.stargazers_count}}
                    </div>
                    <div class="col" v-if ="item.forks > 0">
                        <icon name = "code-fork"/> {{item.forks}}
                    </div>
                    <div class="col" v-if="item.license">
                        <icon name = "balance-scale"/> {{item.license.spdx_id}}
                    </div>
                    <div class="col">
                        Updated {{moment(item.updated_at, "YYYY-MM-DD").fromNow()}}
                    </div>
                </div>
        </div>
    </div>
</template>

<script>
import Icon from 'vue-awesome/components/Icon'
import moment from 'moment'

export default {
    props: ['repoList'],
    data() {
        return {
            moment
        }
    },
    components: {
        Icon
    },
    methods: {
        goTo(index) {
            this.$router.push({path: `/${this.repoList.name}/${this.repoList.repos[index].name}`})
        }
    }
}
</script>

<style scoped lang="less">
    @import "../assets/less/style";
    .repo-list {
        width: 100%;
    }
    .repo-list__container {
        display: flex;
        width: 100%;
        border-bottom: 1px solid lightgrey;
        flex-direction: column;
    }
    .repo-list__link {
        color: @link-color;
        font-size: 18px;
        &:hover {
            text-decoration: underline;
        }
    }
    .row {
        display: flex;
        width: 100%;
        flex-wrap: wrap;
    }
    .repo-list__description {
        font-size: 13px;
    }
    .repo-list__info{
        font-size: 10px;
    }
    .col {
        display: flex;
        padding: 5px;
        svg {
            height: 10px;
        }
    }
</style>
